/**
 * Integration test for exclusion constraint (prevent double-booking)
 * Tests the database-level constraint that prevents overlapping appointments for the same doctor
 */

import { createClient, SupabaseClient } from '@supabase/supabase-js';

describe('Exclusion Constraint - Prevent Double-Booking', () => {
  let supabase: SupabaseClient<any, 'appointments_schema'>;
  const testDoctorId = 'TEST-DOC-000001-001';
  const testPatientId1 = 'PAT-000001-001';
  const testPatientId2 = 'PAT-000002-002';

  beforeAll(() => {
    const supabaseUrl = process.env.SUPABASE_URL!;
    const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY!;

    supabase = createClient(supabaseUrl, supabaseKey, {
      auth: { autoRefreshToken: false, persistSession: false },
      db: { schema: 'appointments_schema' },
    }) as SupabaseClient<any, 'appointments_schema'>;
  });

  afterEach(async () => {
    // Cleanup test data
    await supabase
      .from('appointments')
      .delete()
      .eq('doctor_id', testDoctorId);
  });

  describe('Exclusion Constraint Enforcement', () => {
    it('should allow non-overlapping appointments for same doctor', async () => {
      // Appointment 1: 09:00 - 09:30
      const { error: error1 } = await supabase.from('appointments').insert({
        appointment_id: '2025-APT-000001-001',
        patient_id: testPatientId1,
        doctor_id: testDoctorId,
        appointment_date: '2025-06-01',
        appointment_time: '09:00:00',
        start_at_utc: '2025-06-01T02:00:00Z', // 09:00 ICT
        end_at_utc: '2025-06-01T02:30:00Z',   // 09:30 ICT
        duration_minutes: 30,
        type: 'CONSULTATION',
        status: 'SCHEDULED',
        priority: 'NORMAL',
        payment_status: 'PENDING',
        consultation_fee: 100000,
      });

      expect(error1).toBeNull();

      // Appointment 2: 09:30 - 10:00 (non-overlapping)
      const { error: error2 } = await supabase.from('appointments').insert({
        appointment_id: '2025-APT-000002-002',
        patient_id: testPatientId2,
        doctor_id: testDoctorId,
        appointment_date: '2025-06-01',
        appointment_time: '09:30:00',
        start_at_utc: '2025-06-01T02:30:00Z', // 09:30 ICT
        end_at_utc: '2025-06-01T03:00:00Z',   // 10:00 ICT
        duration_minutes: 30,
        type: 'CONSULTATION',
        status: 'SCHEDULED',
        priority: 'NORMAL',
        payment_status: 'PENDING',
        consultation_fee: 100000,
      });

      expect(error2).toBeNull();
    });

    it('should reject overlapping appointments for same doctor (exact overlap)', async () => {
      // Appointment 1: 10:00 - 10:30
      const { error: error1 } = await supabase.from('appointments').insert({
        appointment_id: '2025-APT-000003-003',
        patient_id: testPatientId1,
        doctor_id: testDoctorId,
        appointment_date: '2025-06-01',
        appointment_time: '10:00:00',
        start_at_utc: '2025-06-01T03:00:00Z',
        end_at_utc: '2025-06-01T03:30:00Z',
        duration_minutes: 30,
        type: 'CONSULTATION',
        status: 'SCHEDULED',
        priority: 'NORMAL',
        payment_status: 'PENDING',
        consultation_fee: 100000,
      });

      expect(error1).toBeNull();

      // Appointment 2: 10:00 - 10:30 (exact overlap)
      const { error: error2 } = await supabase.from('appointments').insert({
        appointment_id: '2025-APT-000004-004',
        patient_id: testPatientId2,
        doctor_id: testDoctorId,
        appointment_date: '2025-06-01',
        appointment_time: '10:00:00',
        start_at_utc: '2025-06-01T03:00:00Z',
        end_at_utc: '2025-06-01T03:30:00Z',
        duration_minutes: 30,
        type: 'CONSULTATION',
        status: 'SCHEDULED',
        priority: 'NORMAL',
        payment_status: 'PENDING',
        consultation_fee: 100000,
      });

      expect(error2).not.toBeNull();
      expect((error2 as any)?.code).toBe('23P01'); // Exclusion constraint violation
      expect((error2 as any)?.message).toContain('exclude_doctor_time_overlap');
    });

    it('should reject overlapping appointments for same doctor (partial overlap - start inside)', async () => {
      // Appointment 1: 11:00 - 11:30
      const { error: error1 } = await supabase.from('appointments').insert({
        appointment_id: '2025-APT-000005-005',
        patient_id: testPatientId1,
        doctor_id: testDoctorId,
        appointment_date: '2025-06-01',
        appointment_time: '11:00:00',
        start_at_utc: '2025-06-01T04:00:00Z',
        end_at_utc: '2025-06-01T04:30:00Z',
        duration_minutes: 30,
        type: 'CONSULTATION',
        status: 'SCHEDULED',
        priority: 'NORMAL',
        payment_status: 'PENDING',
        consultation_fee: 100000,
      });

      expect(error1).toBeNull();

      // Appointment 2: 11:15 - 11:45 (starts inside existing appointment)
      const { error: error2 } = await supabase.from('appointments').insert({
        appointment_id: '2025-APT-000006-006',
        patient_id: testPatientId2,
        doctor_id: testDoctorId,
        appointment_date: '2025-06-01',
        appointment_time: '11:15:00',
        start_at_utc: '2025-06-01T04:15:00Z',
        end_at_utc: '2025-06-01T04:45:00Z',
        duration_minutes: 30,
        type: 'CONSULTATION',
        status: 'SCHEDULED',
        priority: 'NORMAL',
        payment_status: 'PENDING',
        consultation_fee: 100000,
      });

      expect(error2).not.toBeNull();
      expect((error2 as any)?.code).toBe('23P01');
    });

    it('should reject overlapping appointments for same doctor (partial overlap - end inside)', async () => {
      // Appointment 1: 14:00 - 14:30
      const { error: error1 } = await supabase.from('appointments').insert({
        appointment_id: '2025-APT-000007-007',
        patient_id: testPatientId1,
        doctor_id: testDoctorId,
        appointment_date: '2025-06-01',
        appointment_time: '14:00:00',
        start_at_utc: '2025-06-01T07:00:00Z',
        end_at_utc: '2025-06-01T07:30:00Z',
        duration_minutes: 30,
        type: 'CONSULTATION',
        status: 'SCHEDULED',
        priority: 'NORMAL',
        payment_status: 'PENDING',
        consultation_fee: 100000,
      });

      expect(error1).toBeNull();

      // Appointment 2: 13:45 - 14:15 (ends inside existing appointment)
      const { error: error2 } = await supabase.from('appointments').insert({
        appointment_id: '2025-APT-000008-008',
        patient_id: testPatientId2,
        doctor_id: testDoctorId,
        appointment_date: '2025-06-01',
        appointment_time: '13:45:00',
        start_at_utc: '2025-06-01T06:45:00Z',
        end_at_utc: '2025-06-01T07:15:00Z',
        duration_minutes: 30,
        type: 'CONSULTATION',
        status: 'SCHEDULED',
        priority: 'NORMAL',
        payment_status: 'PENDING',
        consultation_fee: 100000,
      });

      expect(error2).not.toBeNull();
      expect((error2 as any)?.code).toBe('23P01');
    });

    it('should reject overlapping appointments for same doctor (complete enclosure)', async () => {
      // Appointment 1: 15:00 - 16:00 (1 hour)
      const { error: error1 } = await supabase.from('appointments').insert({
        appointment_id: '2025-APT-000009-009',
        patient_id: testPatientId1,
        doctor_id: testDoctorId,
        appointment_date: '2025-06-01',
        appointment_time: '15:00:00',
        start_at_utc: '2025-06-01T08:00:00Z',
        end_at_utc: '2025-06-01T09:00:00Z',
        duration_minutes: 60,
        type: 'CONSULTATION',
        status: 'SCHEDULED',
        priority: 'NORMAL',
        payment_status: 'PENDING',
        consultation_fee: 200000,
      });

      expect(error1).toBeNull();

      // Appointment 2: 15:15 - 15:45 (completely inside existing appointment)
      const { error: error2 } = await supabase.from('appointments').insert({
        appointment_id: '2025-APT-000010-010',
        patient_id: testPatientId2,
        doctor_id: testDoctorId,
        appointment_date: '2025-06-01',
        appointment_time: '15:15:00',
        start_at_utc: '2025-06-01T08:15:00Z',
        end_at_utc: '2025-06-01T08:45:00Z',
        duration_minutes: 30,
        type: 'CONSULTATION',
        status: 'SCHEDULED',
        priority: 'NORMAL',
        payment_status: 'PENDING',
        consultation_fee: 100000,
      });

      expect(error2).not.toBeNull();
      expect((error2 as any)?.code).toBe('23P01');
    });

    it('should allow overlapping appointments if one is CANCELLED', async () => {
      // Appointment 1: 16:00 - 16:30 (CANCELLED)
      const { error: error1 } = await supabase.from('appointments').insert({
        appointment_id: '2025-APT-000011-011',
        patient_id: testPatientId1,
        doctor_id: testDoctorId,
        appointment_date: '2025-06-01',
        appointment_time: '16:00:00',
        start_at_utc: '2025-06-01T09:00:00Z',
        end_at_utc: '2025-06-01T09:30:00Z',
        duration_minutes: 30,
        type: 'CONSULTATION',
        status: 'CANCELLED',
        priority: 'NORMAL',
        payment_status: 'PENDING',
        consultation_fee: 100000,
      });

      expect(error1).toBeNull();

      // Appointment 2: 16:00 - 16:30 (SCHEDULED - should be allowed)
      const { error: error2 } = await supabase.from('appointments').insert({
        appointment_id: '2025-APT-000012-012',
        patient_id: testPatientId2,
        doctor_id: testDoctorId,
        appointment_date: '2025-06-01',
        appointment_time: '16:00:00',
        start_at_utc: '2025-06-01T09:00:00Z',
        end_at_utc: '2025-06-01T09:30:00Z',
        duration_minutes: 30,
        type: 'CONSULTATION',
        status: 'SCHEDULED',
        priority: 'NORMAL',
        payment_status: 'PENDING',
        consultation_fee: 100000,
      });

      expect(error2).toBeNull();
    });

    it('should allow same time slots for different doctors', async () => {
      const testDoctorId2 = 'TEST-DOC-000002-002';

      // Doctor 1: 17:00 - 17:30
      const { error: error1 } = await supabase.from('appointments').insert({
        appointment_id: '2025-APT-000013-013',
        patient_id: testPatientId1,
        doctor_id: testDoctorId,
        appointment_date: '2025-06-01',
        appointment_time: '17:00:00',
        start_at_utc: '2025-06-01T10:00:00Z',
        end_at_utc: '2025-06-01T10:30:00Z',
        duration_minutes: 30,
        type: 'CONSULTATION',
        status: 'SCHEDULED',
        priority: 'NORMAL',
        payment_status: 'PENDING',
        consultation_fee: 100000,
      });

      expect(error1).toBeNull();

      // Doctor 2: 17:00 - 17:30 (same time, different doctor - should be allowed)
      const { error: error2 } = await supabase.from('appointments').insert({
        appointment_id: '2025-APT-000014-014',
        patient_id: testPatientId2,
        doctor_id: testDoctorId2,
        appointment_date: '2025-06-01',
        appointment_time: '17:00:00',
        start_at_utc: '2025-06-01T10:00:00Z',
        end_at_utc: '2025-06-01T10:30:00Z',
        duration_minutes: 30,
        type: 'CONSULTATION',
        status: 'SCHEDULED',
        priority: 'NORMAL',
        payment_status: 'PENDING',
        consultation_fee: 100000,
      });

      expect(error2).toBeNull();

      // Cleanup doctor 2
      await supabase.from('appointments').delete().eq('doctor_id', testDoctorId2);
    });
  });
});

